item.validator:
const page_status = this.getValue("page_status");

if (page_status === "View" || !value) {
  callback();
  return;
}

let organizationId = this.getVarGlobal('deptParentId');
if(organizationId === '0'){
    organizationId = this.getVarSystem('deptIds').split(',')[0];
}


db.collection("Item")
  .where({ material_code: value, organization_id: organizationId })
  .get()
  .then((response) => {
    const matchingItems = response.data || [];

    if (matchingItems.length === 0) {
      callback();
      return;
    }

    if (page_status === "Edit") {
      const currentItemId = this.getValue("id");
      const isSameItem = matchingItems.some(
        (item) => item.id === currentItemId
      );
      callback(isSameItem ? undefined : "Item code already exists.");
    } else {
      callback("Item code already exists.");
    }
  })
  .catch((error) => {
    console.error("Error checking item:", error);
    callback("Error validating item code.");
  });

options.validator:
const prefix = value.split(/\d/)[0];
let organizationId = this.getVarGlobal("deptParentId");
if (organizationId === "0") {
    organizationId = this.getVarSystem("deptIds").split(",")[0];
}
db.collection("batch_level_config")
  .where({ organization_id: organizationId })
  .get()
  .then(response => {
    console.log('response', response.data)
    if(response.data.length > 0) {
        let batchPrefix = response.data[0].batch_prefix;

        if(batchPrefix && batchPrefix !== '') {
            batchPrefix = batchPrefix + '-'
        }

        if(batchPrefix === prefix) {
            callback('Prefix is reserved by the system.');
        } else {
            db.collection("batch")
            .where({
                batch_number: value,
                organization_id: organizationId
            })
            .get()
            .then(resBatch => {
                const matchingBatches = resBatch.data || [];

                if (matchingBatches.length > 0 && value) {
                callback('Batch number already exists');
                } else {
                callback();
                }
            })
            .catch(error => {
                console.error("Error checking batch number:", error);
                callback('Error checking batch number');
            });
        }
    }
  })
  .catch(error => {
    console.error("Error checking batch number:", error);
    callback('Error checking batch number');
  });

