      }
    } else {
      for (const [_index, item] of tableSM.entries()) {
        if (item.item_batch_no !== "-") {
          await this.display([
            "stock_movement.manufacturing_date",
            "stock_movement.expired_date",
          ]);
        }
      }
    }
  }
};

