      break;

    case "AutoCount Accounting":
      await this.runWorkflow(
        "2026201453795684354",
        { smr_id: [stockMovementId] },
        () => {
          this.$message.success(
            "Misc Receipt completed and posted successfully.",
          );
          closeDialog();
        },
        (err) => {
          console.error("AutoCount workflow error:", err);
          this.$message.error(
