          );
          closeDialog();
        },
      );
      break;

    case "No Accounting Integration":
      this.$message.success("Misc Receipt completed successfully.");
      closeDialog();
      break;

    case "SQL Accounting V2":
    case "AutoCount Accounting V2":
      this.$message.success("Misc Receipt completed successfully.");
      closeDialog();
      await this.runWorkflow(
        "2013511169625042946",
