  msi_id: [],
})

(async () => {
  const soIDs = arguments[0].value;

  if (soIDs && soIDs.length >= 0) {
    // Fetch SO Data
    const resSO = await Promise.all(
      soIDs.map((id) => db.collection("sales_order").doc(id).get()),
    );

    const soList = resSO.map((response) => response.data[0]);

    // Map SO Data to the MSR Line Items
    let tableMSR = [];
    for (const so of soList) {
      const lineItems = so.table_so || [];
      for (const item of lineItems) {
        console.log('soItem', item)
        tableMSR.push({
          reference_id: so.id,
          reference_no: so.so_no,
          reference_line_id: item.id,
          item_selection: item.item_name,
          item_name: item.item_id,
          item_desc: item.item_desc,
          received_quantity_uom: item.quantity_uom,
          item_remark: item.line_remark_1,
          item_remark_2: item.line_remark_2,
          unit_price: parseFloat(item.so_item_price),
        });
      }
    }
    console.log('tableMSR', tableMSR)

    this.setData({ stock_movement: tableMSR });

    for (let i = 0; i < tableMSR.length; i++) {
