(async () => {
  const msiIDs = arguments[0].value;
  const convertFrom = this.getParamsVariables("convert_from") || "";
  if (msiIDs && msiIDs.length >= 0) {
    // Fetch MSI Data
    const resMSI = await Promise.all(
      msiIDs.map((id) => db.collection("sm_misc_issue").doc(id).get()),
    );

    const msiList = resMSI.map((response) => response.data[0]);

    // Map MSI Data to the MSR Line Items
    let tableMSR = [];
    for (const msi of msiList) {
      const lineItems = msi.stock_movement || [];
      for (const item of lineItems) {
        tableMSR.push({
          reference_id: msi.id,
          reference_no: msi.stock_movement_no,
          reference_line_id: item.id,
          item_selection: item.item_selection,
          item_name: item.item_name,
          item_desc: item.item_desc,
          ...(convertFrom === "MSI"
            ? { received_quantity: item.total_quantity }
            : {}),
          received_quantity_uom: item.quantity_uom,
          item_remark: item.line_remark_1,
          item_remark_2: item.line_remark_2,
          item_remark_3: item.line_remark_3,
        });
      }
    }

    this.setData({ stock_movement: tableMSR });

    for (let i = 0; i < tableMSR.length; i++) {
      const currentItem = tableMSR[i];
      if (currentItem.item_selection) {
        const resItem = await db
          .collection("Item")
          .doc(currentItem.item_selection)
          .get();
        const itemData = resItem.data[0];
        this.triggerEvent("onAfterUpdate_item", {
          rowIndex: i,
          value: currentItem.item_selection,
          fieldModel: { item: itemData },
        });
      }
    }
  }
})();

